import { createSlice } from '@reduxjs/toolkit';


let initialState = {
	isLoginFormOpen:false,
	isRegisterActive:false
}

const accountSlice = createSlice({
	name:'account',
	initialState,
	reducers:{
		openLoginForm:(state) => {
			state.isLoginFormOpen = true
		},
		closeLoginForm:(state) => {
			state.isLoginFormOpen = false
		},
		switchLoginToRegister:(state) => {
			state.isRegisterActive = !state.isRegisterActive
		}
	}
})

export const {openLoginForm, closeLoginForm, switchLoginToRegister} = accountSlice.actions
export const accountSelector = state => state.account
export default accountSlice.reducer
